import React from 'react';
import { useAuth } from '../contexts/AuthContext';

/**
 * Debug component to help identify authentication issues
 * This component shows the current authentication state
 */
const DebugAuth = () => {
  const { user, token, loading, error, isAuthenticated } = useAuth();

  return (
    <div style={{ 
      position: 'fixed', 
      top: '10px', 
      right: '10px', 
      background: 'white', 
      border: '1px solid #ccc', 
      padding: '10px', 
      borderRadius: '5px',
      fontSize: '12px',
      zIndex: 9999,
      maxWidth: '300px'
    }}>
      <h4>Auth Debug Info</h4>
      <div><strong>Loading:</strong> {loading ? 'Yes' : 'No'}</div>
      <div><strong>Authenticated:</strong> {isAuthenticated ? 'Yes' : 'No'}</div>
      <div><strong>Token:</strong> {token ? 'Present' : 'None'}</div>
      <div><strong>User:</strong> {user ? user.name : 'None'}</div>
      <div><strong>Error:</strong> {error || 'None'}</div>
      <div><strong>User Role:</strong> {user?.role || 'None'}</div>
      <div><strong>User Email:</strong> {user?.email || 'None'}</div>
    </div>
  );
};

export default DebugAuth;
